INSERT INTO apartments (
  id, user_id, unit_number, floor, building_no,
  primary_resident_name, secondary_resident_name,
  phone, phone2, email,
  payment_interval, monthly_due_amount, occupancy_status, notes, created_at
)
SELECT
  gen_random_uuid(), auth.uid(),
  s.unit_number, s.floor, s.building_no,
  s.primary_resident_name, s.secondary_resident_name,
  s.phone, s.phone2, s.email,
  s.payment_interval, s.monthly_due_amount, s.occupancy_status, s.notes, now()
FROM apt_src s
WHERE NOT EXISTS (
  SELECT 1 FROM apartments a
  WHERE a.user_id = auth.uid() AND a.unit_number = s.unit_number
);

