INSERT INTO payments (
  id, user_id, apartment_id, payer_name, payer_relation,
  amount, method, date_paid, period_start, period_end,
  recurring, extra, on_dashboard, notes, created_at
)
SELECT
  gen_random_uuid(),
  auth.uid(),
  apt.id,
  src.payer_name,
  src.payer_relation,
  src.amount,
  src.method,
  src.date_paid,
  src.first_month,   -- period_start: first day of the covered month
  -- period_end: last day of last_month
  (date_trunc('month', (src.last_month || '-01')::date) + interval '1 month' - interval '1 day')::date,
  src.recurring,
  src.extra,
  src.on_dashboard,
  src.notes,
  now()
FROM src
JOIN apt ON apt.unit_number = src.unit_number
WHERE NOT EXISTS (
  SELECT 1 FROM payments p2
  WHERE p2.user_id = auth.uid()
    AND p2.apartment_id = apt.id
    AND p2.period_start = src.first_month
    AND p2.extra = src.extra
);

-- ── Verify ────────────────────────────────────────────────────────
-- Run these after the import to confirm the numbers match the sheet.

SELECT COUNT(*) AS apartment_count FROM apartments WHERE user_id = auth.uid();
-- Expected: 56

SELECT COUNT(*) AS payment_rows FROM payments WHERE user_id = auth.uid();
-- Expected: 325 (322 on-dashboard + 3 off-dashboard 2025 settlements)

SELECT
  SUM(amount) FILTER (WHERE on_dashboard AND NOT extra) AS collected_2026,
  SUM(amount) FILTER (WHERE method = 'cash' AND on_dashboard AND NOT extra) AS cash_2026,
  SUM(amount) FILTER (WHERE method = 'bank' AND on_dashboard AND NOT extra) AS bank_2026,
  SUM(amount) FILTER (WHERE NOT on_dashboard OR extra) AS off_dashboard_2025
FROM payments
WHERE user_id = auth.uid();
-- Expected: collected_2026=141550, cash+bank=141550, off_dashboard_2025=6000
